import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import { BarChart, ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PriorityMessage {
  from: string;
  subject: string;
  time: string;
}

interface DailyVolumeTrend {
  day: string;
  emails: number;
}

interface WidgetData {
  unreadCount: number;
  priorityMessages: PriorityMessage[];
  dailyVolumeTrend: DailyVolumeTrend[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#212121', color: '#FFF' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              Mail Monitor
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Unread Emails: {widgetData.unreadCount}
            </Typography>
          </Box>

          <Box>
            <Typography variant="subtitle1" fontWeight={500}>
              Priority Messages
            </Typography>
            <Stack spacing={1}>
              {widgetData.priorityMessages.slice(0, 2).map((message, index) => (
                <Box key={index}>
                  <Typography variant="body2" sx={{ fontWeight: 500 }}>
                    {message.subject}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {message.from} - {message.time}
                  </Typography>
                  {index < widgetData.priorityMessages.length - 1 && <Divider sx={{ my: 1 }} />}
                </Box>
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: widgetData.dailyVolumeTrend.map(d => d.emails),
                  color: '#FF5722',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: widgetData.dailyVolumeTrend.map(d => d.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'emails' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#FFC107' }}
              />
              <ChartsYAxis
                axisId="emails"
                tickLabelStyle={{ fontSize: 10, fill: '#FFC107' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
